                    local trimmed = arg:match("^%s*(.-)%s*$")
                    if trimmed and #trimmed > 0 then
                        cmd_args[#cmd_args + 1] = trimmed
                    end
                end
            end
        end

        return command, cmd_args

    elseif method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()

        if not body then
            return nil, nil, "Empty request body"
        end

        local ok, data = pcall(cjson.decode, body)
        if not ok or type(data) ~= "table" then
            return nil, nil, "Invalid JSON body"
        end

        local command = data.command or data.cmd
        local cmd_args = data.args or data.arguments or {}

        if type(cmd_args) ~= "table" then
            return nil, nil, "Arguments must be an array"
        end

        return command, cmd_args
    else
        return nil, nil, "Only GET and POST methods are supported"
    end
end

